class Solution:
    def distinctSubseqII(self, s):
        MOD = 10**9 + 7
        seen = set()
        cur = ['']
        for ch in s:
            nxt = list(cur)
            for sub in cur:
                nxt.append(sub + ch)
        # brute over all subsequences for small inputs only
        n = len(s)
        subs = set()
        if n <= 16:
            for mask in range(1, 1 << n):
                t = ''.join(s[i] for i in range(n) if mask & (1 << i))
                subs.add(t)
            return len(subs) % MOD
        # fall back to an independent dp formulation for larger inputs
        last = {}
        dp = [0] * (n + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            ch = s[i - 1]
            dp[i] = (2 * dp[i - 1]) % MOD
            if ch in last:
                dp[i] = (dp[i] - dp[last[ch] - 1]) % MOD
            last[ch] = i
        return (dp[n] - 1) % MOD

