class Solution:
    def distinctSubseqII(self, s):
        MOD = 10**9 + 7
        dp = 0
        last = {}
        for ch in s:
            prev = dp
            dp = (2 * dp + 1) % MOD
            if ch in last:
                dp = (dp - last[ch]) % MOD
            last[ch] = prev + 1
        return dp % MOD

