var distinctSubseqII = function(s) {
    const MOD = 1000000007n;
    let dp = 0n;
    const last = new Map();
    for (const ch of s) {
        const prev = dp;
        dp = (2n * dp + 1n) % MOD;
        if (last.has(ch)) {
            dp = (dp - last.get(ch)) % MOD;
        }
        last.set(ch, (prev + 1n) % MOD);
    }
    dp = ((dp % MOD) + MOD) % MOD;
    return Number(dp);
};
